import { Component, h, Prop } from '@stencil/core';
import { EnvironmentBadgeEnvironment, EnvironmentBadgeSite } from '../../models/environment-site-badge.model';

/**
 * Environment + Site badge
 *
 * Renders a wdpr-badge with:
 * - Environment-specific styling (PROD / STAGE / LATEST)
 * - Site code (WDW / DLR / DLP)
 *
 * Visual styling is driven by CSS classes and ::part(surface)
 * so it can be themed from the outside.
 */
@Component({
  tag: 'wdpr-environment-site-badge',
  styleUrl: './wdpr-environment-site-badge.scss',
  shadow: true,
})
export class WdprEnvironmentSiteBadge {
  /**
   * Environment label shown in the badge.
   */
  @Prop({ reflect: true }) environment: EnvironmentBadgeEnvironment = 'LATEST';

  /**
   * Site indicator shown in the badge.
   */
  @Prop({ reflect: true }) site: EnvironmentBadgeSite = 'WDW';

  /**
   * When true, only the environment text is rendered
   * (e.g., "PROD" instead of "PROD • WDW").
   */
  @Prop({ reflect: true }) environmentOnly = false;

  private get _badgeClass(): string {
    switch (this.environment) {
      case 'PROD':
        return 'env-badge env-badge-prod';
      case 'STAGE':
        return 'env-badge env-badge-stage';
      case 'LATEST':
      default:
        return 'env-badge env-badge-latest';
    }
  }

  private get _label(): string {
    if (this.environmentOnly) {
      return this.environment;
    }

    return `${this.environment} • ${this.site}`;
  }

  render() {
    return (
      <wdpr-badge
        class={this._badgeClass}
        surface-class="leading-component-small tracking-02"
        variant="neutral"
        label={this._label}
        role="none"
      ></wdpr-badge>
    );
  }
}
